class DiskCache:
    """Disk-based cache with msgpack serialization and timestamp-based expiration."""

    def __init__(self, cache_dir="cache", default_ttl=300):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        self._lock = threading.Lock()
        os.makedirs(cache_dir, exist_ok=True)

    def _get_cache_path(self, key):
        hashed = hashlib.sha256(key.encode("utf-8")).hexdigest()
        return os.path.join(self.cache_dir, f"{hashed}.msgpack")

    def _serialize(self, data, ttl):
        envelope = {
            "created_at": time.time(),
            "ttl": ttl,
            "data": data,
        }
        return msgpack.packb(envelope, use_bin_type=True)

    def _deserialize(self, raw_bytes):
        return msgpack.unpackb(raw_bytes, raw=False)

    def get(self, key):
        path = self._get_cache_path(key)
        with self._lock:
            if not os.path.exists(path):
                return None
            try:
                with open(path, "rb") as f:
                    raw = f.read()
                envelope = self._deserialize(raw)
                created_at = envelope["created_at"]
                ttl = envelope["ttl"]
                if time.time() - created_at > ttl:
                    os.remove(path)
                    return None
                return envelope["data"]
            except (msgpack.UnpackException, KeyError, OSError):
                # Corrupted cache entry — remove it
                try:
                    os.remove(path)
                except OSError:
                    pass
                return None

    def set(self, key, data, ttl=None):
        if ttl is None:
            ttl = self.default_ttl
        path = self._get_cache_path(key)
        serialized = self._serialize(data, ttl)
        with self._lock:
            tmp_path = path + ".tmp"
            with open(tmp_path, "wb") as f:
                f.write(serialized)
            os.replace(tmp_path, path)

    def delete(self, key):
        path = self._get_cache_path(key)
        with self._lock:
            if os.path.exists(path):
                os.remove(path)
                return True
        return False

    def clear(self):
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if filename.endswith(".msgpack"):
                    filepath = os.path.join(self.cache_dir, filename)
                    try:
                        os.remove(filepath)
                    except OSError:
                        pass

    def cleanup_expired(self):
        """Remove all expired cache entries from disk."""
        now = time.time()
        removed = 0
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                filepath = os.path.join(self.cache_dir, filename)
                try:
                    with open(filepath, "rb") as f:
                        envelope = self._deserialize(f.read())
                    if now - envelope["created_at"] > envelope["ttl"]:
                        os.remove(filepath)
                        removed += 1
                except (msgpack.UnpackException, KeyError, OSError):
                    try:
                        os.remove(filepath)
                        removed += 1
                    except OSError:
                        pass
        return removed

    def stats(self):
        """Return cache statistics."""
        now = time.time()
        total = 0
        expired = 0
        valid = 0
        total_size = 0
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                filepath = os.path.join(self.cache_dir, filename)
                total += 1
                try:
                    total_size += os.path.getsize(filepath)
                    with open(filepath, "rb") as f:
                        envelope = self._deserialize(f.read())
                    if now - envelope["created_at"] > envelope["ttl"]:
                        expired += 1
                    else:
                        valid += 1
                except (msgpack.UnpackException, KeyError, OSError):
                    expired += 1
        return {
            "total_entries": total,
            "valid_entries": valid,
            "expired_entries": expired,
            "total_size_bytes": total_size,
        }


# Initialize the cache
cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_response(ttl=None, key_func=None):
    """Decorator to cache Flask route responses."""

    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            if key_func:
                cache_key = key_func(*args, **kwargs)
            else:
                cache_key = f"{request.method}:{request.path}:{request.query_string.decode('utf-8')}"

            cached_data = cache.get(cache_key)
            if cached_data is not None:
                cached_data["_cache"] = "HIT"
                return jsonify(cached_data)

            response_data = f(*args, **kwargs)
            cache.set(cache_key, response_data, ttl=ttl)
            response_data["_cache"] = "MISS"
            return jsonify(response_data)

        return wrapper

    return decorator


